preToolUse.powershell:
$mode = if ($env:VSTACK_HOOKS_MODE) { $env:VSTACK_HOOKS_MODE } else { 'audit' }
if ($mode -ne 'enforce') {
  exit 0
}
$inputText = [Console]::In.ReadToEnd()
function Write-HookLog {
  param([string]$Message)
  $logName = if ($env:VSTACK_HOOK_LOG_NAME) { $env:VSTACK_HOOK_LOG_NAME } else { 'hook-security-alerts.log' }
  $logRoot = if ($env:VSTACK_HOOK_LOG_DIR) { $env:VSTACK_HOOK_LOG_DIR } else { '.vstack/logs' }
  $logDir = Join-Path $logRoot (Get-Date).ToUniversalTime().ToString('yyyyMMdd')
  New-Item -ItemType Directory -Force -Path $logDir | Out-Null
  Add-Content -Path (Join-Path $logDir $logName) -Value $Message
}
try {
  $payload = $inputText | ConvertFrom-Json -ErrorAction Stop
} catch {
  Write-HookLog 'payload-parse-failed'
  @{ permissionDecision = 'deny'; permissionDecisionReason = 'Blocked request because payload could not be validated in enforce mode' } | ConvertTo-Json -Compress
  exit 0
}
if (-not $payload.toolName) {
  Write-HookLog 'payload-parse-failed'
  @{ permissionDecision = 'deny'; permissionDecisionReason = 'Blocked request because payload could not be validated in enforce mode' } | ConvertTo-Json -Compress
  exit 0
}
if ($payload.toolName -eq 'bash' -and $inputText -match 'rm -rf /|mkfs|dd if=|DROP TABLE|TRUNCATE TABLE|git reset --hard|git clean -fdx|shutdown -h|shutdown now|reboot|poweroff|halt') {
  Write-HookLog 'destructive-command-blocked'
  @{ permissionDecision = 'deny'; permissionDecisionReason = 'Blocked potentially destructive shell command by vstack pre-tool safety policy' } | ConvertTo-Json -Compress
}
